import type { ReactElement, ReactNode } from "react";
import { useState } from "react";

import { CardTile } from "@/components/card-tile";
import { SkillPreviewModal } from "@/skills/skill-preview-modal";

export function SkillPreviewCardShell({
  cardIcon,
  cardTitle,
  cardDescription,
  cardBadges,
  cardActions,
  cardClassName,
  modalTitle,
  modalTitleClassName,
  modalTitleText,
  modalDescription,
  modalSuggestedPrompt,
  modalSkillPath,
  modalFooter,
}: {
  cardIcon: ReactElement;
  cardTitle: ReactNode;
  cardDescription: string;
  cardBadges?: Array<ReactNode>;
  cardActions?:
    | ReactNode
    | ((params: { openPreview: () => void }) => ReactNode);
  cardClassName?: string;
  modalTitle: ReactNode;
  modalTitleClassName?: string;
  modalTitleText?: string;
  modalDescription: string;
  modalSuggestedPrompt?: string | null;
  modalSkillPath: string | null;
  modalFooter?:
    | ReactNode
    | ((params: { closePreview: () => void }) => ReactNode);
}): ReactElement {
  const [isDialogOpen, setIsDialogOpen] = useState(false);
  const openPreview = (): void => {
    setIsDialogOpen(true);
  };
  const closePreview = (): void => {
    setIsDialogOpen(false);
  };

  return (
    <>
      <CardTile
        className={cardClassName}
        icon={cardIcon}
        title={cardTitle}
        description={cardDescription}
        descriptionClassName="line-clamp-1"
        badges={cardBadges}
        actions={
          typeof cardActions === "function"
            ? cardActions({ openPreview })
            : cardActions
        }
        actionsPlacement="center"
        onClick={openPreview}
      />
      <SkillPreviewModal
        icon={cardIcon}
        title={modalTitle}
        titleClassName={modalTitleClassName}
        titleText={modalTitleText}
        description={modalDescription}
        suggestedPrompt={modalSuggestedPrompt}
        skillPath={modalSkillPath}
        isOpen={isDialogOpen}
        onOpenChange={setIsDialogOpen}
        footer={
          typeof modalFooter === "function"
            ? modalFooter({ closePreview })
            : modalFooter
        }
      />
    </>
  );
}
