import clsx from "clsx";
import type { ReactElement, ReactNode } from "react";

import { Button } from "@/components/button";
import { Dialog } from "@/components/dialog";
import {
  DIALOG_FOOTER_COMPACT,
  DialogBody,
  DialogFooter,
  DialogHeader,
  DialogSection,
} from "@/components/dialog-layout";

export function ProseModal({
  icon,
  title,
  titleClassName,
  description,
  descriptionClassName,
  children,
  isOpen,
  onOpenChange,
  footer,
  loading,
  error,
  className,
  loadingMessage,
  errorMessage,
  closeLabel,
  scrollFade = true,
  footerSectionClassName,
}: {
  icon?: ReactElement | null;
  title: ReactNode;
  titleClassName?: string;
  description?: string;
  descriptionClassName?: string;
  children: ReactNode;
  isOpen: boolean;
  onOpenChange: (nextValue: boolean) => void;
  footer?: ReactNode;
  loading?: boolean;
  error?: string;
  className?: string;
  loadingMessage?: ReactNode;
  errorMessage?: ReactNode;
  closeLabel?: ReactNode;
  scrollFade?: boolean;
  footerSectionClassName?: string;
}): ReactElement {
  return (
    <Dialog
      contentClassName={clsx("!p-0", className)}
      open={isOpen}
      onOpenChange={onOpenChange}
      size="editor"
    >
      <DialogBody size="full">
        <DialogSection>
          <DialogHeader
            icon={icon}
            iconClassName="h-12 w-12 rounded-xl !p-0"
            iconBackgroundClassName="bg-transparent"
            title={title}
            subtitle={description}
            titleClassName={clsx("text-token-foreground", titleClassName)}
            subtitleClassName={clsx(
              "text-token-text-secondary",
              descriptionClassName,
            )}
          />
        </DialogSection>
        <DialogSection className="flex-1 min-h-0">
          <div
            className={clsx(
              "h-full overflow-y-auto opacity-80",
              scrollFade ? "vertical-scroll-fade-mask" : null,
            )}
          >
            {loading ? (
              <div className="text-token-text-secondary">{loadingMessage}</div>
            ) : error ? (
              <div className="text-token-text-secondary">
                {errorMessage ?? error}
              </div>
            ) : (
              children
            )}
          </div>
        </DialogSection>
        <DialogSection className={footerSectionClassName}>
          <DialogFooter className={DIALOG_FOOTER_COMPACT}>
            {footer ? (
              footer
            ) : (
              <Button
                color="ghost"
                size="toolbar"
                onClick={() => onOpenChange(false)}
              >
                {closeLabel}
              </Button>
            )}
          </DialogFooter>
        </DialogSection>
      </DialogBody>
    </Dialog>
  );
}
