import { useAtomValue } from "jotai";
import type { ReactElement } from "react";
import { FormattedMessage } from "react-intl";

import { aAppUpdateReady } from "@/app-update-ready-atom";
import { messageBus } from "@/message-bus";

export function AppUpdateButton(): ReactElement | null {
  const isUpdateReady = useAtomValue(aAppUpdateReady);

  if (!isUpdateReady) {
    return null;
  }

  return (
    <button
      className="no-drag h-5 rounded-full bg-token-charts-blue px-2.5 text-[10px] font-semibold leading-none text-white shadow-sm transition-colors hover:bg-token-charts-blue/90 active:bg-token-charts-blue/80"
      onClick={(): void => {
        messageBus.dispatchMessage("install-app-update", {});
      }}
    >
      <FormattedMessage
        id="appHeader.installUpdate"
        defaultMessage="Update"
        description="Button label in the desktop app header that installs a downloaded app update"
      />
    </button>
  );
}
