import type { HostConfig, MessageForView } from "protocol";
import { type ReactElement, useState } from "react";
import { defineMessages, FormattedMessage } from "react-intl";

import { Badge } from "@/components/badge";
import { useMessage } from "@/message-bus";

type AppServerConnectionChangedMessage = Extract<
  MessageForView,
  { type: "codex-app-server-connection-changed" }
>;

const remoteConnectionStatusBadgeMessages = defineMessages({
  connecting: {
    id: "threadPage.remoteConnectionStatusBadge.connecting",
    defaultMessage: "Connecting",
    description: "Label shown when remote connection is in progress",
  },
  connected: {
    id: "threadPage.remoteConnectionStatusBadge.connected",
    defaultMessage: "Connected",
    description: "Label shown when remote connection is established",
  },
  disconnected: {
    id: "threadPage.remoteConnectionStatusBadge.disconnected",
    defaultMessage: "Disconnected",
    description: "Label shown when remote connection is unavailable",
  },
});

const V2_REMOTE_BOX_WEBSOCKET_CONNECTION_MESSAGE_BY_STATE: Record<
  AppServerConnectionChangedMessage["state"],
  (typeof remoteConnectionStatusBadgeMessages)[keyof typeof remoteConnectionStatusBadgeMessages]
> = {
  connecting: remoteConnectionStatusBadgeMessages.connecting,
  connected: remoteConnectionStatusBadgeMessages.connected,
  disconnected: remoteConnectionStatusBadgeMessages.disconnected,
};

export function RemoteConnectionStatusBadge({
  hostConfig,
}: {
  hostConfig: HostConfig;
}): ReactElement | null {
  const [currentConnectionStateMessage, setCurrentConnectionStateMessage] =
    useState<AppServerConnectionChangedMessage | null>(null);

  useMessage(
    "codex-app-server-connection-changed",
    (message): void => {
      setCurrentConnectionStateMessage(message);
    },
    [],
  );

  if (!isV2RemoteBoxWebsocketHostConfig(hostConfig)) {
    return null;
  }

  const displayedConnectionState =
    getDisplayedConnectionStateForV2RemoteBoxWebsocketConnection(
      currentConnectionStateMessage,
    );
  if (displayedConnectionState == null) {
    return null;
  }

  return (
    <Badge className="self-center rounded-full px-2.5 py-0.5 leading-none">
      <FormattedMessage
        {...V2_REMOTE_BOX_WEBSOCKET_CONNECTION_MESSAGE_BY_STATE[
          displayedConnectionState
        ]}
      />
    </Badge>
  );
}

function isRemoteHostConfig(hostConfig: HostConfig): boolean {
  return hostConfig.kind !== "local";
}

function isV2RemoteBoxWebsocketHostConfig(hostConfig: HostConfig): boolean {
  if (!isRemoteHostConfig(hostConfig)) {
    return false;
  }
  return typeof hostConfig.websocket_url === "string";
}

function getDisplayedConnectionStateForV2RemoteBoxWebsocketConnection(
  currentConnectionStateMessage: AppServerConnectionChangedMessage | null,
): AppServerConnectionChangedMessage["state"] | null {
  if (currentConnectionStateMessage == null) {
    return "connected";
  }
  if (currentConnectionStateMessage.transport !== "websocket") {
    return null;
  }
  return currentConnectionStateMessage.state;
}
