import { useExperimentalFeatures } from "@/queries/experimental-features-queries";
import { useGate } from "@/statsig/statsig";

export function useIsAppsEnabled(): boolean {
  const { data: experimentalFeatures = [] } = useExperimentalFeatures();
  const isCodexRolloutEnabled = useGate(__statsigName("codex_rollout_apps"));
  return (
    isCodexRolloutEnabled &&
    experimentalFeatures.some((feature) => {
      return feature.name === "apps" && feature.enabled;
    })
  );
}
