import path from "path";

import { useQueryClient } from "@tanstack/react-query";
import type * as AppServer from "app-server-types";
import type { RecommendedSkillMetadata } from "protocol";
import type { CSSProperties, ReactElement, ReactNode } from "react";
import { useCallback, useMemo, useState } from "react";
import { FormattedMessage, useIntl } from "react-intl";
import { useLocation } from "react-router";

import { useUpdateAppEnabled } from "@/apps/apps-availability";
import { useAppConnectFlow } from "@/apps/use-app-connect-flow";
import { Badge } from "@/components/badge";
import { Button } from "@/components/button";
import { CompoundButton } from "@/components/compound-button";
import { Dropdown } from "@/components/dropdown";
import { LargeEmptyState } from "@/components/large-empty-state";
import { useToaster } from "@/components/toaster/toaster";
import { escapePromptLinkPath } from "@/composer/prosemirror/prompt-link-path";
import {
  CHATGPT_APPS_FEATURES_URL,
  CHATGPT_DEVELOPERS_APPS_URL,
  CODEX_SKILLS_URL,
} from "@/constants/links";
import type { HomeLocationState } from "@/home-page";
import { useStartNewConversation } from "@/hooks/use-start-new-conversation";
import ArrowRotateCwIcon from "@/icons/arrow-rotate-cw.svg";
import FolderIcon from "@/icons/folder.svg";
import NewAppIcon from "@/icons/new-app.svg";
import PlusIcon from "@/icons/plus.svg";
import SearchIcon from "@/icons/search.svg";
import SkillsIcon from "@/icons/skills.svg";
import { useProductEvents } from "@/product-events";
import { useAppsListWithResolvedConnectorLogos } from "@/queries/apps-queries";
import { AppConnectModal } from "@/settings/settings-content/app-connect-modal";
import { useSharedObject } from "@/shared-objects/use-shared-object";
import { AppCard } from "@/skills/app-card";
import {
  formatSkillScopeLabel,
  getRepoLabelFromRoots,
} from "@/skills/format-skill-scope";
import { RecommendedSkillCard } from "@/skills/recommended-skill-card";
import { SkillCard } from "@/skills/skill-card";
import { getSkillDisplayName } from "@/skills/skill-utils";
import {
  partitionAppsByAccessibility,
  selectFilteredDirectoryApps,
  selectFilteredInstalledSkills,
  selectFilteredRecommendedSkills,
  selectOrderedRecommendedDirectoryApps,
  selectOrderedRecommendedTabDirectoryApps,
  selectOrderedWhitelistedRecommendedSkills,
  selectRecommendedTabApps,
  selectRecommendedTabRecommendedSkills,
} from "@/skills/skills-apps-page-selectors";
import { ThreadPageHeader } from "@/thread-layout/thread-page-header";
import { useElementInView } from "@/utils/use-element-in-view";
import {
  getQueryKey,
  useFetchFromVSCode,
  useMutationFromVSCode,
} from "@/vscode-api";

import { useRecommendedSkills } from "./use-recommended-skills";
import { useSkills } from "./use-skills";

const SKILLS_SECTIONS_GAP_STYLE = {
  "--skills-sections-gap": "calc(var(--spacing) * 9)",
} as CSSProperties;

const SCOPE_RANK: Record<AppServer.v2.SkillScope, number> = {
  repo: 0,
  user: 1,
  system: 2,
  admin: 3,
};
type SkillsAppsPageTab = "recommended" | "skills" | "apps";
type CreateItemId = "skill" | "app";

export function SkillsAppsPage(): ReactElement {
  const intl = useIntl();
  const location = useLocation();
  const routeState = getSkillsAppsPageRouteState(location.state);
  const logProductEvent = useProductEvents();
  const startNewConversation = useStartNewConversation();
  const queryClient = useQueryClient();
  const toast = useToaster();
  const [scrollContainer, setScrollContainer] = useState<HTMLDivElement | null>(
    null,
  );
  const [heroContainer, setHeroContainer] = useState<HTMLDivElement | null>(
    null,
  );
  const setScrollContainerRef = useCallback((node: HTMLDivElement | null) => {
    setScrollContainer(node);
  }, []);
  const setHeroContainerRef = useCallback((node: HTMLDivElement | null) => {
    setHeroContainer(node);
  }, []);
  const isHeroVisible = useElementInView({
    container: scrollContainer,
    target: heroContainer,
  });

  const [selectedTab, setSelectedTab] = useState<SkillsAppsPageTab>(() => {
    return routeState.initialTab;
  });
  const [oauthCallbackAppId, setOauthCallbackAppId] = useState<string | null>(
    () => routeState.connectAppId ?? null,
  );
  const [selectedCreateItemId, setSelectedCreateItemId] =
    useState<CreateItemId>("skill");
  const [showAllRecommendedApps, setShowAllRecommendedApps] = useState(false);
  const [searchQuery, setSearchQuery] = useState("");
  const [installingSkillId, setInstallingSkillId] = useState<string | null>(
    null,
  );
  const [isRefreshingPage, setIsRefreshingPage] = useState(false);

  const { data: workspaceRoots } = useFetchFromVSCode("workspace-root-options");
  const { data: codexHomeData } = useFetchFromVSCode("codex-home");
  const roots = workspaceRoots?.roots ?? [];
  const skillsRoots = roots.length > 0 ? roots : undefined;

  const { skills, isLoading, isFetching, forceReload } = useSkills(skillsRoots);
  const uniqueSkills = dedupeSkills(skills);
  const [, setSkillsRefreshNonce] = useSharedObject("skills_refresh_nonce");
  const [needsSkillsRefresh, setNeedsSkillsRefresh] = useState(false);
  const {
    data: recommendedSkillsData,
    isLoading: isRecommendedLoading,
    errorMessage: recommendedErrorMessage,
    refresh: refreshRecommendedSkills,
  } = useRecommendedSkills({
    enabled: true,
  });
  const recommendedSkills = recommendedSkillsData?.skills ?? [];
  const recommendedRepoRoot =
    recommendedSkillsData?.repoRoot ??
    (codexHomeData?.codexHome
      ? path.join(codexHomeData.codexHome, "vendor_imports", "skills")
      : null);
  const {
    data: directoryApps = [],
    hardRefetchAppsList,
    isHardRefetchingAppsList,
  } = useAppsListWithResolvedConnectorLogos();
  const { setAppEnabled, isUpdating: isUpdatingAppEnablement } =
    useUpdateAppEnabled();
  const {
    connectingApp,
    clearConnectingApp,
    handleAppConnectOAuthStarted,
    handleConnectApp,
    handleOpenAppUrl,
    isAppConnectPending,
  } = useAppConnectFlow();
  const oauthCallbackApp = useMemo(() => {
    if (oauthCallbackAppId == null) {
      return null;
    }
    return (
      directoryApps.find((app) => {
        return app.id === oauthCallbackAppId;
      }) ?? null
    );
  }, [directoryApps, oauthCallbackAppId]);
  const isCompletingOauthConnection =
    oauthCallbackAppId != null && isAppConnectPending(oauthCallbackAppId);
  const modalApp = connectingApp ?? oauthCallbackApp;

  const handleSkillsUpdated = (): void => {
    void queryClient.invalidateQueries({ queryKey: ["skills"] });
    void forceReload();
    setSkillsRefreshNonce((previous) => (previous ?? 0) + 1);
  };

  const installSkillMutation = useMutationFromVSCode(
    "install-recommended-skill",
    {
      onSuccess: (response, variables): void => {
        if (response.success) {
          void queryClient.invalidateQueries({
            queryKey: getQueryKey("recommended-skills", { refresh: false }),
          });
          handleSkillsUpdated();
          setNeedsSkillsRefresh(true);
          const installedSkill = recommendedSkills.find(
            (skill) => skill.id === variables.skillId,
          );
          if (installedSkill) {
            toast.success(
              <FormattedMessage
                id="skills.recommended.installSuccess"
                defaultMessage="{skillName} skill installed"
                description="Toast shown after successfully installing a recommended skill"
                values={{
                  skillName: (
                    <span className="font-medium">{installedSkill.name}</span>
                  ),
                }}
              />,
            );
          }
        }
      },
      onSettled: (): void => {
        setInstallingSkillId(null);
      },
    },
  );

  const installedSkillIds = useMemo(
    () =>
      new Set(
        uniqueSkills
          .map(({ skill }) => getSkillIdFromPath(skill.path))
          .filter((id): id is string => id != null),
      ),
    [uniqueSkills],
  );
  const installedSkillsById = useMemo(() => {
    return uniqueSkills.reduce<Map<string, AppServer.v2.SkillMetadata>>(
      (acc, { skill }) => {
        const skillId = getSkillIdFromPath(skill.path);
        if (skillId == null) {
          return acc;
        }
        acc.set(skillId, skill);
        return acc;
      },
      new Map(),
    );
  }, [uniqueSkills]);

  const searchQueryNormalized = searchQuery.trim().toLowerCase();
  const hasSearchQuery = searchQueryNormalized.length > 0;
  const filteredInstalledSkills = selectFilteredInstalledSkills({
    skills: uniqueSkills,
    query: searchQueryNormalized,
  });
  const filteredRecommendedSkills = selectFilteredRecommendedSkills({
    skills: recommendedSkills,
    query: searchQueryNormalized,
  });
  const orderedFilteredWhitelistedRecommendedSkills =
    selectOrderedWhitelistedRecommendedSkills(filteredRecommendedSkills);
  const filteredDirectoryApps = selectFilteredDirectoryApps({
    apps: directoryApps,
    query: searchQueryNormalized,
  });
  const orderedFilteredRecommendedDirectoryApps =
    selectOrderedRecommendedDirectoryApps(filteredDirectoryApps);
  const orderedFilteredRecommendedTabDirectoryApps =
    selectOrderedRecommendedTabDirectoryApps(filteredDirectoryApps);

  const skillCreatorPath = codexHomeData?.codexHome
    ? `${codexHomeData.codexHome}/skills/.system/skill-creator/SKILL.md`
    : null;
  const scopeFilterRepoLabel = formatSkillScopeLabel({
    scope: "repo",
    intl,
  });

  const handleCreateSkill = (): void => {
    if (!skillCreatorPath) {
      return;
    }
    logProductEvent({
      eventName: "codex_skill_new_clicked",
    });
    const prompt = `[$skill-creator](${escapePromptLinkPath(skillCreatorPath)}) `;
    const state: HomeLocationState = {
      prefillPrompt: prompt,
    };
    startNewConversation(state, { startInSidebar: true });
  };

  const handleCreateApp = (): void => {
    window.open(CHATGPT_DEVELOPERS_APPS_URL, "_blank", "noopener,noreferrer");
  };

  const handleCreateAction = (id: CreateItemId): void => {
    setSelectedCreateItemId(id);
    if (id === "skill") {
      handleCreateSkill();
      return;
    }
    handleCreateApp();
  };

  const handleInstallRecommendedSkill = (
    skill: RecommendedSkillMetadata,
    installRoot: string | null,
  ): void => {
    if (!codexHomeData?.codexHome) {
      return;
    }
    setInstallingSkillId(skill.id);
    installSkillMutation.mutate({
      skillId: skill.id,
      repoPath: skill.repoPath,
      installRoot,
    });
  };
  const handleConnectAppFromPage = async (
    app: AppServer.v2.AppInfo,
  ): Promise<void> => {
    setOauthCallbackAppId(null);
    await handleConnectApp(app);
  };
  const handleToggleAppEnabled = async ({
    appId,
    nextEnabled,
  }: {
    appId: string;
    nextEnabled: boolean;
  }): Promise<void> => {
    try {
      await setAppEnabled({
        appId,
        enabled: nextEnabled,
      });
    } catch (_error) {
      // Error is logged by the mutation hook.
    }
  };
  const handleRefreshPage = async (): Promise<void> => {
    setIsRefreshingPage(true);
    try {
      await Promise.all([
        forceReload(),
        refreshRecommendedSkills(),
        hardRefetchAppsList(),
      ]);
      setNeedsSkillsRefresh(false);
    } catch {
      toast.danger(
        intl.formatMessage({
          id: "skills.page.refreshFailed",
          defaultMessage: "Failed to refresh skills and apps",
          description:
            "Toast message shown when refreshing the Skills & Apps page data fails",
        }),
      );
    } finally {
      setIsRefreshingPage(false);
    }
  };
  const isRefreshButtonLoading = isRefreshingPage || isHardRefetchingAppsList;

  const {
    installedApps: filteredInstalledApps,
    discoverApps: filteredAllDiscoverApps,
  } = partitionAppsByAccessibility(filteredDirectoryApps);
  const filteredDiscoverAppsSource =
    hasSearchQuery || showAllRecommendedApps
      ? filteredDirectoryApps
      : orderedFilteredRecommendedDirectoryApps;
  const { discoverApps: filteredDiscoverApps } = partitionAppsByAccessibility(
    filteredDiscoverAppsSource,
  );
  const recommendedSkillsForTab = hasSearchQuery
    ? filteredRecommendedSkills
    : orderedFilteredWhitelistedRecommendedSkills;
  const appsForRecommendedTab = hasSearchQuery
    ? filteredAllDiscoverApps
    : orderedFilteredRecommendedTabDirectoryApps;
  const recommendedTabRecommendedSkills = selectRecommendedTabRecommendedSkills(
    {
      recommendedSkills: recommendedSkillsForTab,
      installedSkillIds,
    },
  );
  const recommendedTabApps = selectRecommendedTabApps({
    installedApps: filteredInstalledApps,
    recommendedTabApps: appsForRecommendedTab,
  });
  const searchPlaceholder = getSearchPlaceholder(intl, selectedTab);
  const searchLabel = getSearchLabel(intl, selectedTab);
  const canInstallRecommendedSkills = codexHomeData?.codexHome != null;
  const selectedCreateItemLabel =
    selectedCreateItemId === "skill" ? (
      <FormattedMessage
        id="skills.appsPage.createSkill"
        defaultMessage="New skill"
        description="Button label for creating a new skill on the Skills & Apps page"
      />
    ) : (
      <FormattedMessage
        id="skills.appsPage.createApp"
        defaultMessage="New app"
        description="Menu item label for creating a new app on the Skills & Apps page"
      />
    );
  const handleSelectTab = (nextTab: SkillsAppsPageTab): void => {
    if (nextTab !== "apps") {
      setShowAllRecommendedApps(false);
    }
    setSelectedTab(nextTab);
  };

  return (
    <div className="skills-page-surface flex h-full min-h-0 flex-col text-base">
      <ThreadPageHeader
        start={
          isHeroVisible ? null : (
            <FormattedMessage
              id="skills.appsPage.heading"
              defaultMessage="Skills & Apps"
              description="Header title for the Skills & Apps page"
            />
          )
        }
        hideDivider={isHeroVisible}
        trailing={
          <div className="inline-flex shrink-0 items-center gap-2">
            <Button
              color={needsSkillsRefresh ? "secondary" : "ghost"}
              size="toolbar"
              loading={isRefreshButtonLoading}
              onClick={(): void => {
                void handleRefreshPage();
              }}
              disabled={isLoading || isFetching}
            >
              <ArrowRotateCwIcon className="icon-xs" />
              <span className="hidden lg:inline">
                {needsSkillsRefresh ? (
                  <FormattedMessage
                    id="skills.page.refreshSkillsToUseNew"
                    defaultMessage="Refresh to use new skill(s)"
                    description="Button label shown when newly installed skills require a refresh before they can be used in the composer"
                  />
                ) : (
                  <FormattedMessage
                    id="skills.page.refreshSkills"
                    defaultMessage="Refresh"
                    description="Button label for reloading skills list"
                  />
                )}
              </span>
            </Button>
            <div className="hidden shrink-0 lg:flex">
              <SkillsAppsSearchBar
                searchQuery={searchQuery}
                onSearchQueryChange={setSearchQuery}
                placeholder={searchPlaceholder}
                label={searchLabel}
              />
            </div>
            <CompoundButton
              color="primary"
              size="toolbar"
              onClick={() => {
                handleCreateAction(selectedCreateItemId);
              }}
              primaryDisabled={
                selectedCreateItemId === "skill" && !skillCreatorPath
              }
              dropdownAlign="end"
              dropdownContentClassName="pt-2"
              dropdownContent={
                <>
                  <Dropdown.Title>
                    <FormattedMessage
                      id="skills.appsPage.createMenu.title"
                      defaultMessage="Create"
                      description="Dropdown title for the create menu on the Skills & Apps page"
                    />
                  </Dropdown.Title>
                  <Dropdown.Item
                    disabled={!skillCreatorPath}
                    onSelect={() => {
                      handleCreateAction("skill");
                    }}
                  >
                    <CreateDropdownItemRow
                      Icon={SkillsIcon}
                      label={
                        <FormattedMessage
                          id="skills.appsPage.createSkill"
                          defaultMessage="New skill"
                          description="Button label for creating a new skill on the Skills & Apps page"
                        />
                      }
                    />
                  </Dropdown.Item>
                  <Dropdown.Item
                    onSelect={() => {
                      handleCreateAction("app");
                    }}
                  >
                    <CreateDropdownItemRow
                      Icon={NewAppIcon}
                      label={
                        <FormattedMessage
                          id="skills.appsPage.createApp"
                          defaultMessage="New app"
                          description="Menu item label for creating a new app on the Skills & Apps page"
                        />
                      }
                    />
                  </Dropdown.Item>
                </>
              }
            >
              <CreateDropdownItemRow
                Icon={PlusIcon}
                label={selectedCreateItemLabel}
              />
            </CompoundButton>
          </div>
        }
      />
      <div
        className="p-panel flex-1 overflow-y-auto"
        ref={setScrollContainerRef}
      >
        <div
          className="skills-page-container mx-auto flex min-h-full w-full max-w-[1100px] flex-1 flex-col gap-8 pb-10"
          style={SKILLS_SECTIONS_GAP_STYLE}
        >
          <div className="flex flex-col gap-1" ref={setHeroContainerRef}>
            <div className="heading-xl font-normal text-token-foreground">
              <FormattedMessage
                id="skills.appsPage.heading"
                defaultMessage="Skills & Apps"
                description="Header title for the Skills & Apps page"
              />
            </div>
            <div className="text-lg font-normal text-token-description-foreground">
              <FormattedMessage
                id="skills.appsPage.subheading"
                defaultMessage="Give Codex superpowers with <skillsLink>Skills</skillsLink> and <appsLink>Apps</appsLink>"
                description="Subheading shown above the Skills & Apps sections"
                values={{
                  skillsLink: (chunks) => (
                    <a
                      href={CODEX_SKILLS_URL}
                      target="_blank"
                      rel="noopener noreferrer"
                      className="text-token-link"
                    >
                      {chunks}
                    </a>
                  ),
                  appsLink: (chunks) => (
                    <a
                      href={CHATGPT_APPS_FEATURES_URL}
                      target="_blank"
                      rel="noopener noreferrer"
                      className="text-token-link"
                    >
                      {chunks}
                    </a>
                  ),
                }}
              />
            </div>
          </div>
          <FilterChipRow
            chips={[
              {
                id: "recommended",
                label: (
                  <FormattedMessage
                    id="skills.appsPage.tab.recommended"
                    defaultMessage="Recommended/Installed"
                    description="Chip label for the recommended section on the Skills & Apps page"
                  />
                ),
              },
              {
                id: "skills",
                label: (
                  <FormattedMessage
                    id="skills.appsPage.tab.skills"
                    defaultMessage="Skills"
                    description="Chip label for the skills section on the Skills & Apps page"
                  />
                ),
              },
              {
                id: "apps",
                label: (
                  <FormattedMessage
                    id="skills.appsPage.tab.apps"
                    defaultMessage="Apps"
                    description="Chip label for the apps section on the Skills & Apps page"
                  />
                ),
              },
            ]}
            selectedChip={selectedTab}
            onSelect={handleSelectTab}
          />

          {selectedTab === "recommended" ? (
            <div className="flex flex-col gap-[var(--skills-sections-gap)]">
              <ContentSection
                title={
                  <FormattedMessage
                    id="skills.appsPage.section.skills"
                    defaultMessage="Skills"
                    description="Section heading for skills on the Skills & Apps page"
                  />
                }
                action={undefined}
              >
                <RecommendedSkillsGrid
                  isLoading={isRecommendedLoading}
                  errorMessage={recommendedErrorMessage}
                  skills={recommendedTabRecommendedSkills}
                  canInstall={canInstallRecommendedSkills}
                  repoRoot={recommendedRepoRoot}
                  onInstall={handleInstallRecommendedSkill}
                  installedSkillIds={installedSkillIds}
                  installedSkillsById={installedSkillsById}
                  installingSkillId={installingSkillId}
                  roots={roots}
                  scopeFilterRepoLabel={scopeFilterRepoLabel}
                  onSkillsUpdated={handleSkillsUpdated}
                  leadingInstalledSkillEntries={filteredInstalledSkills}
                />
              </ContentSection>

              <ContentSection
                title={
                  <FormattedMessage
                    id="skills.appsPage.section.apps"
                    defaultMessage="Apps"
                    description="Section heading for apps on the Skills & Apps page"
                  />
                }
                action={undefined}
              >
                <AppsCardsGrid
                  apps={recommendedTabApps}
                  isAppConnectPending={isAppConnectPending}
                  onInstallApp={handleConnectAppFromPage}
                  onOpenAppUrl={handleOpenAppUrl}
                  onToggleAppEnabled={handleToggleAppEnabled}
                  isUpdatingAppEnablement={isUpdatingAppEnablement}
                  emptyStateTitle={
                    <FormattedMessage
                      id="skills.appsPage.empty.apps"
                      defaultMessage="No apps found"
                      description="Empty state title when no apps match filters on the Skills & Apps page"
                    />
                  }
                />
              </ContentSection>
            </div>
          ) : null}

          {selectedTab === "skills" ? (
            <div className="flex flex-col gap-[var(--skills-sections-gap)]">
              <ContentSection
                title={
                  <FormattedMessage
                    id="skills.appsPage.section.installedSkills"
                    defaultMessage="Installed"
                    description="Heading for the installed skills section"
                  />
                }
              >
                <InstalledSkillsGrid
                  skillEntries={filteredInstalledSkills}
                  roots={roots}
                  scopeFilterRepoLabel={scopeFilterRepoLabel}
                  onSkillsUpdated={handleSkillsUpdated}
                />
              </ContentSection>

              <ContentSection
                title={
                  <FormattedMessage
                    id="skills.appsPage.section.recommendedSkills"
                    defaultMessage="Recommended"
                    description="Heading for the recommended skills section"
                  />
                }
              >
                <RecommendedSkillsGrid
                  isLoading={isRecommendedLoading}
                  errorMessage={recommendedErrorMessage}
                  skills={filteredRecommendedSkills}
                  canInstall={canInstallRecommendedSkills}
                  repoRoot={recommendedRepoRoot}
                  onInstall={handleInstallRecommendedSkill}
                  installedSkillIds={installedSkillIds}
                  installedSkillsById={installedSkillsById}
                  installingSkillId={installingSkillId}
                  roots={roots}
                  scopeFilterRepoLabel={scopeFilterRepoLabel}
                  onSkillsUpdated={handleSkillsUpdated}
                />
              </ContentSection>
            </div>
          ) : null}

          {selectedTab === "apps" ? (
            <div className="flex flex-col gap-[var(--skills-sections-gap)]">
              <ContentSection
                title={
                  <FormattedMessage
                    id="skills.appsPage.section.installedApps"
                    defaultMessage="Installed"
                    description="Section heading for installed apps on the Skills & Apps page"
                  />
                }
              >
                <AppsCardsGrid
                  apps={filteredInstalledApps}
                  isAppConnectPending={isAppConnectPending}
                  onInstallApp={handleConnectAppFromPage}
                  onOpenAppUrl={handleOpenAppUrl}
                  onToggleAppEnabled={handleToggleAppEnabled}
                  isUpdatingAppEnablement={isUpdatingAppEnablement}
                  emptyStateTitle={
                    <FormattedMessage
                      id="skills.appsPage.empty.installedApps"
                      defaultMessage="No installed apps"
                      description="Empty state title when there are no installed apps on the Skills & Apps page"
                    />
                  }
                />
              </ContentSection>

              <ContentSection
                title={
                  <FormattedMessage
                    id="skills.appsPage.section.discover"
                    defaultMessage="Recommended"
                    description="Section heading for discoverable apps on the Skills & Apps page"
                  />
                }
                action={
                  <div className="flex items-center gap-2">
                    <Button
                      color="ghost"
                      size="toolbar"
                      loading={isHardRefetchingAppsList}
                      onClick={(): void => {
                        void hardRefetchAppsList();
                      }}
                    >
                      <ArrowRotateCwIcon className="icon-2xs" />
                      <FormattedMessage
                        id="settings.mcp.apps.refresh"
                        defaultMessage="Refresh"
                        description="Button label to hard refresh the app list in MCP settings"
                      />
                    </Button>
                    {filteredAllDiscoverApps.length > 0 ? (
                      <Button
                        color="ghost"
                        size="toolbar"
                        onClick={(): void => {
                          setShowAllRecommendedApps(
                            (currentValue) => !currentValue,
                          );
                        }}
                      >
                        {showAllRecommendedApps ? (
                          <FormattedMessage
                            id="skills.appsPage.section.discover.hideFullList"
                            defaultMessage="Hide full list"
                            description="Button label to hide the full apps list and return to recommended apps in the Skills & Apps page"
                          />
                        ) : (
                          <FormattedMessage
                            id="skills.appsPage.section.discover.seeAll"
                            defaultMessage="View all {count} apps"
                            description="Button label to show all apps in the recommended apps section on the Skills & Apps page"
                            values={{ count: filteredAllDiscoverApps.length }}
                          />
                        )}
                      </Button>
                    ) : null}
                  </div>
                }
              >
                <AppsCardsGrid
                  apps={filteredDiscoverApps}
                  isAppConnectPending={isAppConnectPending}
                  onInstallApp={handleConnectAppFromPage}
                  onOpenAppUrl={handleOpenAppUrl}
                  onToggleAppEnabled={handleToggleAppEnabled}
                  isUpdatingAppEnablement={isUpdatingAppEnablement}
                  emptyStateTitle={
                    <FormattedMessage
                      id="skills.appsPage.empty.discoverApps"
                      defaultMessage="No apps found"
                      description="Empty state title when there are no discoverable apps on the Skills & Apps page"
                    />
                  }
                />
              </ContentSection>
            </div>
          ) : null}
        </div>
        <AppConnectModal
          app={modalApp}
          isCompletingConnection={isCompletingOauthConnection}
          open={modalApp != null}
          onOpenChange={(nextOpen): void => {
            if (!nextOpen) {
              clearConnectingApp();
              setOauthCallbackAppId(null);
            }
          }}
          onOAuthStarted={handleAppConnectOAuthStarted}
          onConnected={async (): Promise<void> => {
            setOauthCallbackAppId(null);
            await hardRefetchAppsList();
          }}
        />
      </div>
    </div>
  );
}

