function InstalledSkillCardItem({
  skill,
  roots,
  scopeFilterRepoLabel,
  onSkillsUpdated,
}: {
  skill: AppServer.v2.SkillMetadata;
  roots: Array<string>;
  scopeFilterRepoLabel: string;
  onSkillsUpdated: () => void;
}): ReactElement {
  const scopeBadges =
    skill.scope === "repo"
      ? [
          <RepoScopeBadge
            key={`${skill.path}-repo`}
            label={getRepoLabelFromRoots({
              skillPath: skill.path,
              roots,
              fallbackLabel: scopeFilterRepoLabel,
            })}
          />,
        ]
      : [];

  const repoRoot =
    skill.scope === "repo"
      ? getRepoRootForSkillPath({
          skillPath: skill.path,
          roots,
        })
      : null;

  return (
    <SkillCard
      skill={skill}
      displayName={getSkillDisplayName(skill)}
      scopeBadges={scopeBadges}
      repoRoot={repoRoot}
      onSkillsUpdated={onSkillsUpdated}
    />
  );
}

function RecommendedSkillsGrid({
  isLoading,
  errorMessage,
  skills,
  canInstall,
  repoRoot,
  onInstall,
  installedSkillIds,
  installedSkillsById,
  installingSkillId,
  roots,
  scopeFilterRepoLabel,
  onSkillsUpdated,
  leadingInstalledSkillEntries,
}: {
  isLoading: boolean;
  errorMessage: string | null;
  skills: Array<RecommendedSkillMetadata>;
  canInstall: boolean;
  repoRoot: string | null;
  onInstall: (
    skill: RecommendedSkillMetadata,
    installRoot: string | null,
  ) => void;
  installedSkillIds: Set<string>;
  installedSkillsById: Map<string, AppServer.v2.SkillMetadata>;
  installingSkillId: string | null;
  roots: Array<string>;
  scopeFilterRepoLabel: string;
  onSkillsUpdated: () => void;
  leadingInstalledSkillEntries?: Array<{
    skill: AppServer.v2.SkillMetadata;
  }>;
}): ReactElement {
  const installedLeadingEntries = leadingInstalledSkillEntries ?? [];

  if (isLoading && installedLeadingEntries.length === 0) {
    return (
      <div className="flex min-h-0 flex-1 items-center justify-center py-8">
        <LargeEmptyState
          title={
            <FormattedMessage
              id="skills.page.loading"
              defaultMessage="Loading skills..."
              description="Loading label on the skills page"
            />
          }
        />
      </div>
    );
  }

  if (errorMessage && installedLeadingEntries.length === 0) {
    return (
      <div className="flex min-h-0 flex-1 items-center justify-center py-8">
        <LargeEmptyState
          title={
            <FormattedMessage
              id="skills.recommended.error"
              defaultMessage="Unable to load recommended skills"
              description="Error title when recommended skills fail to load"
            />
          }
          description={errorMessage}
        />
      </div>
    );
  }

  const visibleSkills = skills.filter(
    (skill) => !installedSkillIds.has(skill.id),
  );
  const hasVisibleInstalledLeadingSkills = installedLeadingEntries.length > 0;

  if (visibleSkills.length === 0 && !hasVisibleInstalledLeadingSkills) {
    return (
      <div className="flex min-h-0 flex-1 items-center justify-center py-8">
        <LargeEmptyState
          title={
            <FormattedMessage
              id="skills.appsPage.empty.skills"
              defaultMessage="No skills found"
              description="Empty state title when no skills match filters on the Skills & Apps page"
            />
          }
        />
      </div>
    );
  }

  return (
    <div className="skills-grid grid gap-4">
      {installedLeadingEntries.map(
        ({ skill: installedSkill }): ReactElement => {
          return (
            <InstalledSkillCardItem
              key={installedSkill.path}
              skill={installedSkill}
              roots={roots}
              scopeFilterRepoLabel={scopeFilterRepoLabel}
              onSkillsUpdated={onSkillsUpdated}
            />
          );
        },
      )}
      {visibleSkills.map((skill) => {
        const installedSkill = installedSkillsById.get(skill.id);
        if (installedSkill) {
          return (
            <InstalledSkillCardItem
              key={installedSkill.path}
              skill={installedSkill}
              roots={roots}
              scopeFilterRepoLabel={scopeFilterRepoLabel}
              onSkillsUpdated={onSkillsUpdated}
            />
          );
        }

        return (
          <RecommendedSkillCard
            key={skill.id}
            skill={skill}
            canInstall={canInstall}
            isInstalled={installedSkillIds.has(skill.id)}
            isInstalling={installingSkillId === skill.id}
            repoRoot={repoRoot}
            onInstall={onInstall}
          />
        );
      })}
    </div>
  );
}

