function getRepoRootForSkillPath({
  skillPath,
  roots,
}: {
  skillPath: string;
  roots: Array<string>;
}): string | null {
  let bestRoot: string | null = null;
  for (const root of roots) {
    if (!skillPath.startsWith(root)) {
      continue;
    }
    if (!bestRoot || root.length > bestRoot.length) {
      bestRoot = root;
    }
  }
  return bestRoot;
}

function getSkillIdFromPath(skillPath: string): string | null {
  const normalized = skillPath.replace(/[\\/]+$/, "");
  const segments = normalized.split(/[\\/]/).filter(Boolean);
  if (segments.length === 0) {
    return null;
  }
  const last = segments[segments.length - 1];
  if (last.toLowerCase() === "skill.md" && segments.length > 1) {
    return segments[segments.length - 2];
  }
  if (last.toLowerCase().endsWith(".md")) {
    return last.slice(0, -3);
  }
  return last;
}

