function getSkillsAppsPageRouteState(value: unknown): {
  connectAppId?: string;
  initialTab: SkillsAppsPageTab;
} {
  if (value == null || typeof value !== "object") {
    return {
      initialTab: "recommended",
    };
  }

  const initialTabValue = Reflect.get(value, "initialTab");
  const connectAppIdValue = Reflect.get(value, "connectAppId");
  const connectAppId =
    typeof connectAppIdValue === "string" ? connectAppIdValue.trim() : null;
  const initialTab: SkillsAppsPageTab =
    initialTabValue === "recommended" ||
    initialTabValue === "skills" ||
    initialTabValue === "apps"
      ? initialTabValue
      : "recommended";

  if (connectAppId == null || connectAppId.length === 0) {
    return {
      initialTab,
    };
  }

  return {
    connectAppId,
    initialTab,
  };
}

function dedupeSkills(skills: Array<AppServer.v2.SkillMetadata>): Array<{
  skill: AppServer.v2.SkillMetadata;
}> {
  const byName = skills.reduce<
    Map<
      string,
      {
        skill: AppServer.v2.SkillMetadata;
      }
    >
  >((acc, skill): typeof acc => {
    const existing = acc.get(skill.name);
    if (existing) {
      const nextRank = SCOPE_RANK[skill.scope];
      const currentRank = SCOPE_RANK[existing.skill.scope];
      if (
        nextRank < currentRank ||
        (nextRank === currentRank &&
          skill.path.localeCompare(existing.skill.path) < 0)
      ) {
        existing.skill = skill;
      }
      return acc;
    }
    acc.set(skill.name, {
      skill,
    });
    return acc;
  }, new Map());

  return Array.from(byName.values())
    .map(({ skill }) => ({ skill }))
    .sort((a, b): number => a.skill.name.localeCompare(b.skill.name));
}
