import clsx from "clsx";
import type { HTMLAttributes, ReactElement, ReactNode } from "react";
import { FormattedMessage, useIntl } from "react-intl";

import { CodeSnippet } from "@/components/code-snippet";
import { Markdown } from "@/components/markdown";
import { ProseModal } from "@/components/prose-modal";
import { Spinner } from "@/components/spinner";
import { useSkillMarkdown } from "@/skills/use-skill-markdown";

const SKILL_MARKDOWN_HEADING_BASE_CLASS_NAME = "font-semibold";

export function SkillPreviewModal({
  icon,
  title,
  titleClassName,
  titleText,
  description,
  suggestedPrompt,
  skillPath,
  isOpen,
  onOpenChange,
  footer,
}: {
  icon: ReactElement | null;
  title: ReactNode;
  titleClassName?: string;
  titleText?: string;
  description: string;
  suggestedPrompt?: string | null;
  skillPath: string | null;
  isOpen: boolean;
  onOpenChange: (nextValue: boolean) => void;
  footer?: ReactNode;
}): ReactElement {
  const intl = useIntl();
  const trimmedSuggestedPrompt = suggestedPrompt?.trim();
  const hasSuggestedPrompt =
    trimmedSuggestedPrompt != null && trimmedSuggestedPrompt.length > 0;
  const { markdown, isFetching, error } = useSkillMarkdown({
    path: skillPath,
    expectedTitle: titleText,
    enabled: isOpen && skillPath != null,
  });
  const hasError = error != null || (isOpen && skillPath == null);

  return (
    <ProseModal
      icon={icon}
      title={title}
      titleClassName={titleClassName}
      description={description}
      descriptionClassName="text-lg"
      isOpen={isOpen}
      onOpenChange={onOpenChange}
      loading={isFetching}
      error={hasError ? "contentsError" : undefined}
      loadingMessage={
        <div className="text-token-text-secondary flex items-center gap-2 text-sm">
          <Spinner className="icon-xs" />
          <FormattedMessage
            id="skills.card.loadingContents"
            defaultMessage="Loading skill contents..."
            description="Loading label when fetching a skill file preview"
          />
        </div>
      }
      errorMessage={
        <div className="text-token-text-secondary text-sm">
          <FormattedMessage
            id="skills.card.contentsError"
            defaultMessage="Unable to load skill contents."
            description="Error message when a skill file preview fails"
          />
        </div>
      }
      closeLabel={
        <FormattedMessage
          id="common.close"
          defaultMessage="Close"
          description="Close button label"
        />
      }
      scrollFade={false}
      footer={footer}
    >
      <div
        className={clsx(
          "flex h-full min-h-0 flex-col gap-4",
          hasSuggestedPrompt ? "pt-0" : "pt-4",
        )}
      >
        {hasSuggestedPrompt ? (
          <CodeSnippet
            wrapperClassName="text-sm"
            content={trimmedSuggestedPrompt}
            language="plaintext"
            title={
              <FormattedMessage
                id="skills.preview.examplePrompt"
                defaultMessage="Example prompt"
                description="Title shown above the sample prompt in the skill preview modal"
              />
            }
            copyButtonText={intl.formatMessage({
              id: "skills.preview.copyPrompt",
              defaultMessage: "Copy prompt",
              description:
                "Tooltip text for the button that copies the sample prompt in the skill preview modal",
            })}
            shouldWrapCode
            codeClassName="break-words"
          />
        ) : null}
        <div className="flex min-h-0 flex-1 flex-col overflow-hidden rounded-xl border border-token-border-default/70">
          <div className="h-full min-h-0 overflow-y-auto p-4">
            <Markdown
              className="text-sm"
              components={{
                h1: SkillMarkdownH1,
                h2: SkillMarkdownH2,
              }}
              cwd={null}
            >
              {markdown}
            </Markdown>
          </div>
        </div>
      </div>
    </ProseModal>
  );
}

function SkillMarkdownH1({
  children,
  className,
  ...rest
}: HTMLAttributes<HTMLHeadingElement>): ReactElement {
  return (
    <h1
      {...rest}
      className={clsx(
        SKILL_MARKDOWN_HEADING_BASE_CLASS_NAME,
        "heading-base mt-4 mb-2",
        className,
      )}
    >
      {children}
    </h1>
  );
}

function SkillMarkdownH2({
  children,
  className,
  ...rest
}: HTMLAttributes<HTMLHeadingElement>): ReactElement {
  return (
    <h2
      {...rest}
      className={clsx(
        SKILL_MARKDOWN_HEADING_BASE_CLASS_NAME,
        "text-sm mt-3 mb-1.5",
        className,
      )}
    >
      {children}
    </h2>
  );
}
