import clsx from "clsx";
import type { CSSProperties, ReactElement } from "react";

import { Button } from "@/components/button";
import { WithWindow } from "@/components/with-window";
import { useStartNewConversation } from "@/hooks/use-start-new-conversation";
import Compose from "@/icons/compose.svg";

import { useAppShell } from "./app-shell-context";
import { AppUpdateButton } from "./app-update-button";
import { SidebarTrigger } from "./sidebar-trigger";

export const APP_HEADER_SIDEBAR_PORTAL_ID = "app-header-portal-sidebar";
export const APP_HEADER_MAIN_PORTAL_ID = "app-header-portal-main";
export const APP_HEADER_DIVIDER_PORTAL_ID = "app-header-portal-divider";

export function AppHeaderPortal({
  isResizing,
}: {
  isResizing: boolean;
}): ReactElement {
  const { isSidebarOpen } = useAppShell();
  const startNewChat = useStartNewConversation();
  const handleStartNewChat = (): void => startNewChat();
  const collapsedLeftWidth =
    "calc(var(--spacing-token-safe-header-left) + (var(--spacing-token-button-composer) * 2) + (var(--spacing) * 3))";
  const sidebarColumnStyle = isSidebarOpen
    ? undefined
    : ({ minWidth: collapsedLeftWidth } as CSSProperties);
  const mainInsetStyle = {
    "--app-header-main-inset": isSidebarOpen ? "0px" : collapsedLeftWidth,
    "--app-header-main-right-inset": "var(--spacing-token-safe-header-right)",
    paddingRight:
      "calc(var(--padding-panel) + var(--app-header-main-right-inset, 0px))",
  } as CSSProperties;

  return (
    <div className="draggable pointer-events-none fixed inset-x-0 top-0 z-30">
      <div className="relative">
        <div
          className={clsx(
            "app-header-tint absolute top-0 right-0 z-0 h-toolbar rounded-tl-lg pointer-events-none will-change-[left]",
            isResizing
              ? "transition-none"
              : "transition-[left] duration-relaxed ease-basic",
            isSidebarOpen ? "left-token-sidebar" : "left-0",
          )}
        />
      </div>
      <div className="relative z-10 h-toolbar pointer-events-auto flex items-center">
        <div
          className={clsx(
            "app-header-left h-toolbar pl-token-safe-header-left will-change-width duration-relaxed ease-basic relative flex min-w-0 flex-shrink-0 items-center justify-between overflow-hidden",
            isResizing ? "transition-none" : "transition-width",
            isSidebarOpen ? "min-w-token-sidebar" : "min-w-px",
          )}
          style={sidebarColumnStyle}
        >
          <div className="flex items-center gap-1.5">
            <SidebarTrigger />
            <Button
              uniform
              color="ghost"
              onClick={handleStartNewChat}
              size="toolbar"
              className={isSidebarOpen ? "pointer-events-none opacity-0" : ""}
            >
              <Compose className="icon-sm" />
            </Button>
          </div>

          <div
            className={clsx(
              "app-header-left-portal h-toolbar flex min-w-0 flex-1 items-center justify-end gap-1.5 overflow-hidden pr-2",
              isSidebarOpen ? null : "pl-2",
            )}
          >
            <WithWindow electron>
              <AppUpdateButton />
            </WithWindow>
            <div
              className={clsx(
                // This wrapper controls visibility/width when the sidebar is open/closed, while
                // keeping the portal node itself "as-is".
                "flex-none overflow-hidden duration-relaxed ease-basic",
                isResizing
                  ? "transition-none"
                  : "transition-[max-width,opacity]",
                isSidebarOpen
                  ? "max-w-none opacity-100"
                  : "pointer-events-none max-w-0 opacity-0",
              )}
            >
              <div id={APP_HEADER_SIDEBAR_PORTAL_ID}></div>
            </div>
          </div>
        </div>
        <div className="h-toolbar flex min-w-0 flex-1 items-center">
          <div
            id={APP_HEADER_MAIN_PORTAL_ID}
            className="px-panel flex min-w-0 flex-1"
            style={mainInsetStyle}
          />
        </div>
      </div>

      <div
        id={APP_HEADER_DIVIDER_PORTAL_ID}
        className={clsx(
          "pointer-events-none absolute bottom-0 left-0 right-0 h-px w-full",
          isSidebarOpen ? "left-token-sidebar" : "left-0",
        )}
      />
    </div>
  );
}
