import {
  createContext,
  useContext,
  useMemo,
  useState,
  type PropsWithChildren,
  type ReactElement,
} from "react";

/* oxlint-disable react/only-export-components */
import { useMessage } from "@/message-bus";

interface AppShellContextValue {
  isSidebarOpen: boolean;
  showSidebar: () => void;
  hideSidebar: () => void;
  toggleSidebar: () => void;
}

const AppShellContext = createContext<AppShellContextValue | null>(null);

/**
 * Provides layout toggles so shell children can mutate sidebar visibility.
 */
export function AppShellProvider({
  children,
}: PropsWithChildren): ReactElement {
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  useMessage(
    "toggle-sidebar",
    () => {
      setIsSidebarOpen((open) => !open);
    },
    [],
  );
  const value = useMemo<AppShellContextValue>(
    () => ({
      isSidebarOpen,
      showSidebar: (): void => {
        setIsSidebarOpen(true);
      },
      hideSidebar: (): void => {
        setIsSidebarOpen(false);
      },
      toggleSidebar: (): void => {
        setIsSidebarOpen((open) => !open);
      },
    }),
    [isSidebarOpen],
  );
  return (
    <AppShellContext.Provider value={value}>
      {children}
    </AppShellContext.Provider>
  );
}

/**
 * Returns the current AppShell context, ensuring consumers sit under provider.
 */
export function useAppShell(): AppShellContextValue {
  const value = useContext(AppShellContext);
  if (value == null) {
    throw new Error("useAppShell must be used inside AppShellProvider");
  }
  return value;
}

/**
 * Returns the shell context when present, otherwise null for conditional UIs.
 */
export function useOptionalAppShell(): AppShellContextValue | null {
  return useContext(AppShellContext);
}
