const SCOPE_RANK: Record<AppServer.v2.SkillScope, number> = {
  repo: 0,
  user: 1,
  system: 2,
  admin: 3,
};

function dedupeSkills(skills: Array<AppServer.v2.SkillMetadata>): Array<{
  skill: AppServer.v2.SkillMetadata;
  scopes: Set<AppServer.v2.SkillScope>;
}> {
  const byName = skills.reduce<
    Map<
      string,
      {
        skill: AppServer.v2.SkillMetadata;
        scopes: Set<AppServer.v2.SkillScope>;
      }
    >
  >((acc, skill): typeof acc => {
    const existing = acc.get(skill.name);
    if (existing) {
      existing.scopes.add(skill.scope);
      const nextRank = SCOPE_RANK[skill.scope];
      const currentRank = SCOPE_RANK[existing.skill.scope];
      if (
        nextRank < currentRank ||
        (nextRank === currentRank &&
          skill.path.localeCompare(existing.skill.path) < 0)
      ) {
        existing.skill = skill;
      }
      return acc;
    }
    acc.set(skill.name, {
      skill,
      scopes: new Set([skill.scope]),
    });
    return acc;
  }, new Map());

  return Array.from(byName.values())
    .map(({ skill, scopes }) => ({
      skill,
      scopes,
    }))
    .sort((a, b): number => a.skill.name.localeCompare(b.skill.name));
}

export function SkillsPage(): ReactElement {
  const appsFeatureEnabled = useIsAppsEnabled();
  if (appsFeatureEnabled) {
    return <SkillsAppsPage />;
  }
  return <SkillsTab />;
}

function SkillsTab(): ReactElement {
  const intl = useIntl();
  const logProductEvent = useProductEvents();
  const { data: account } = useCurrentAccount();
  const startNewConversation = useStartNewConversation();
  const queryClient = useQueryClient();
  const skillsLearnMoreUrl = CODEX_SKILLS_URL;
  const toast = useToaster();
  const [scrollContainer, setScrollContainer] = useState<HTMLDivElement | null>(
    null,
  );
  const [heroContainer, setHeroContainer] = useState<HTMLDivElement | null>(
    null,
  );
  const setScrollContainerRef = useCallback((node: HTMLDivElement | null) => {
    setScrollContainer(node);
  }, []);
  const setHeroContainerRef = useCallback((node: HTMLDivElement | null) => {
    setHeroContainer(node);
  }, []);
  const isHeroVisible = useElementInView({
    container: scrollContainer,
    target: heroContainer,
  });
  const { data: workspaceRoots } = useFetchFromVSCode("workspace-root-options");
  const { data: codexHomeData } = useFetchFromVSCode("codex-home");
  const roots = useMemo<Array<string>>(
    () => workspaceRoots?.roots ?? [],
    [workspaceRoots?.roots],
  );
  const skillsRoots = useMemo<Array<string> | undefined>(() => {
    if (roots.length > 0) {
      return roots;
    }
    return undefined;
  }, [roots]);
  const { skills, isLoading, isFetching, forceReload } = useSkills(skillsRoots);
  const uniqueSkills = dedupeSkills(skills);
  const [installingSkillId, setInstallingSkillId] = useState<string | null>(
    null,
  );
  const [, setSkillsRefreshNonce] = useSharedObject("skills_refresh_nonce");
  const [needsSkillsRefresh, setNeedsSkillsRefresh] = useState(false);
  const [searchQuery, setSearchQuery] = useState("");
  const handleSkillsUpdated = (): void => {
    void queryClient.invalidateQueries({ queryKey: ["skills"] });
    void forceReload();
    setSkillsRefreshNonce((previous) => (previous ?? 0) + 1);
  };
  const {
    data: recommendedSkillsData,
    isLoading: isRecommendedLoading,
    errorMessage: recommendedErrorMessage,
    refresh: refreshRecommendedSkills,
  } = useRecommendedSkills({
    enabled: true,
  });
  const recommendedSkills = recommendedSkillsData?.skills ?? [];
  const installSkillMutation = useMutationFromVSCode(
    "install-recommended-skill",
    {
      onSuccess: (response, variables): void => {
        if (response.success) {
          void queryClient.invalidateQueries({
            queryKey: getQueryKey("recommended-skills", { refresh: false }),
          });
          handleSkillsUpdated();
          setNeedsSkillsRefresh(true);
          const installedSkill = recommendedSkills.find(
            (skill) => skill.id === variables.skillId,
          );
          if (installedSkill) {
            toast.success(
              <FormattedMessage
                id="skills.recommended.installSuccess"
                defaultMessage="{skillName} skill installed"
                description="Toast shown after successfully installing a recommended skill"
                values={{
                  skillName: (
                    <span className="font-medium">{installedSkill.name}</span>
                  ),
                }}
              />,
            );
          }
        }
      },
      onSettled: (): void => {
        setInstallingSkillId(null);
      },
    },
  );
  const recommendedRepoRoot =
    recommendedSkillsData?.repoRoot ??
    (codexHomeData?.codexHome
      ? path.join(codexHomeData.codexHome, "vendor_imports", "skills")
      : null);
  const skillCreatorPath = codexHomeData?.codexHome
    ? `${codexHomeData.codexHome}/skills/.system/skill-creator/SKILL.md`
    : null;
  const scopeFilterRepoLabel = formatSkillScopeLabel({
    scope: "repo",
    intl,
  });
  const scopeFilterAdminLabel = formatSkillScopeLabel({
    scope: "admin",
    intl,
    adminLabel: account?.name ?? undefined,
  });
  const getScopeBadgeLabel = ({
    scope,
    skillPath,
  }: {
    scope: AppServer.v2.SkillScope;
    skillPath: string;
  }): string => {
    return formatSkillScopeLabel({
      scope,
      intl,
      repoLabel: getRepoLabelFromRoots({
        skillPath,
        roots,
        fallbackLabel: scopeFilterRepoLabel,
      }),
      adminLabel: scopeFilterAdminLabel,
    });
  };

  const searchQueryNormalized = searchQuery.trim().toLowerCase();
  const filteredInstalledSkills = uniqueSkills.filter(({ skill }) => {
    if (searchQueryNormalized.length === 0) {
      return true;
    }
    const description = getSkillDescription(skill).toLowerCase();
    const displayName = getSkillDisplayName(skill).toLowerCase();
    return (
      skill.name.toLowerCase().includes(searchQueryNormalized) ||
      displayName.includes(searchQueryNormalized) ||
      description.includes(searchQueryNormalized)
    );
  });

  const installedSkillIds = new Set(
    uniqueSkills
      .map(({ skill }) => getSkillIdFromPath(skill.path))
      .filter((id): id is string => id != null),
  );
  const handleInstallRecommendedSkill = (
    skill: RecommendedSkillMetadata,
    installRoot: string | null,
  ): void => {
    if (!codexHomeData?.codexHome) {
      return;
    }
    setInstallingSkillId(skill.id);
    installSkillMutation.mutate({
      skillId: skill.id,
      repoPath: skill.repoPath,
      installRoot,
    });
  };
  const handleRefreshSkills = async (): Promise<void> => {
    await Promise.all([forceReload(), refreshRecommendedSkills()]);
    setNeedsSkillsRefresh(false);
  };

  useEffect(() => {
    document.documentElement.dataset.hideHeaderDivider = "true";
    return (): void => {
      delete document.documentElement.dataset.hideHeaderDivider;
    };
  }, []);

  return (
    <div className="skills-page-surface flex h-full flex-col text-base">
      <ThreadPageHeader
        start={
          isHeroVisible ? null : (
            <FormattedMessage
              id="skills.page.heading"
              defaultMessage="Skills"
              description="Header title for the skills page"
            />
          )
        }
        trailing={
          <div className="flex flex-nowrap items-center gap-1.5">
            <Button
              color={needsSkillsRefresh ? "secondary" : "ghost"}
              size="toolbar"
              onClick={(): void => {
                void handleRefreshSkills();
              }}
              disabled={isLoading || isFetching}
            >
              <ArrowRotateCwIcon className="icon-xs" />
              <span className="hidden lg:inline">
                {needsSkillsRefresh ? (
                  <FormattedMessage
                    id="skills.page.refreshSkillsToUseNew"
                    defaultMessage="Refresh to use new skill(s)"
                    description="Button label shown when newly installed skills require a refresh before they can be used in the composer"
                  />
                ) : (
                  <FormattedMessage
                    id="skills.page.refreshSkills"
                    defaultMessage="Refresh"
                    description="Button label for reloading skills list"
                  />
                )}
              </span>
            </Button>
            <div className="hidden min-w-[160px] flex-1 lg:flex lg:flex-none lg:w-[220px]">
              <SkillsSearchBar
                searchQuery={searchQuery}
                onSearchQueryChange={setSearchQuery}
              />
            </div>
            <Button
              color="primary"
              size="toolbar"
              onClick={(): void => {
                if (!skillCreatorPath) {
                  return;
                }
                logProductEvent({
                  eventName: "codex_skill_new_clicked",
                });
                const prompt = `[$skill-creator](${escapePromptLinkPath(
                  skillCreatorPath,
                )}) `;
                const state: HomeLocationState = {
                  prefillPrompt: prompt,
                };
                // In VS Code settings webview, keep Settings open and prefill the sidebar composer.
                startNewConversation(state, { startInSidebar: true });
              }}
              disabled={!skillCreatorPath}
            >
              <PlusIcon className="icon-xs" />
              <FormattedMessage
                id="skills.page.createSkill"
                defaultMessage="New skill"
                description="Button label for creating a new skill"
              />
            </Button>
          </div>
        }
      />
      <div
        className="p-panel flex-1 overflow-y-auto"
        ref={setScrollContainerRef}
      >
        <div className="skills-page-container mx-auto flex min-h-full w-full max-w-[1100px] flex-1 flex-col gap-8">
          <div className="flex items-end justify-between gap-4">
            <div className="flex flex-col gap-1" ref={setHeroContainerRef}>
              <div className="heading-xl font-normal text-token-foreground">
                <FormattedMessage
                  id="skills.page.heading"
                  defaultMessage="Skills"
                  description="Header title for the skills page"
                />
              </div>
              <div className="text-lg font-normal text-token-description-foreground">
                <FormattedMessage
                  id="skills.page.subheading"
                  defaultMessage="Give Codex superpowers. <link>Learn more</link>"
                  description="Subheading shown above the skills sections"
                  values={{
                    link: (chunks) => (
                      <a
                        href={skillsLearnMoreUrl}
                        target="_blank"
                        rel="noopener noreferrer"
                        className="text-token-link"
                      >
                        {chunks}
                      </a>
                    ),
                  }}
                />
              </div>
            </div>
          </div>
          <div className="flex min-h-0 flex-1 w-full">
            <div className="flex min-h-0 flex-1 flex-col gap-9 pb-10">
              <SkillsSection
                title={
                  <FormattedMessage
                    id="skills.section.installed"
                    defaultMessage="Installed"
                    description="Heading for the installed skills section"
                  />
                }
              >
                <SkillsGrid
                  isLoading={isLoading}
                  uniqueSkillCount={uniqueSkills.length}
                  filteredSkills={filteredInstalledSkills}
                  getScopeBadgeLabel={getScopeBadgeLabel}
                  roots={roots}
                  onSkillsUpdated={handleSkillsUpdated}
                />
              </SkillsSection>

              <SkillsSection
                title={
                  <FormattedMessage
                    id="skills.section.recommended"
                    defaultMessage="Recommended"
                    description="Heading for the recommended skills section"
                  />
                }
              >
                <RecommendedSkillsGrid
                  isLoading={isRecommendedLoading}
                  errorMessage={recommendedErrorMessage}
                  skills={recommendedSkills}
                  searchQuery={searchQuery}
                  canInstall={codexHomeData?.codexHome != null}
                  repoRoot={recommendedRepoRoot}
                  onInstall={handleInstallRecommendedSkill}
                  installedSkillIds={installedSkillIds}
                  installingSkillId={installingSkillId}
                />
              </SkillsSection>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

function SkillsSection({
  title,
  children,
}: {
  title: ReactElement;
  children: ReactElement;
}): ReactElement {
  return (
    <section className="flex flex-col gap-4">
      <div className="text-token-foreground text-base font-medium opacity-75 pl-2 pr-0.5">
        {title}
      </div>
      {children}
    </section>
  );
}

function SkillsSearchBar({
  searchQuery,
  onSearchQueryChange,
}: {
  searchQuery: string;
  onSearchQueryChange: (value: string) => void;
}): ReactElement {
  const intl = useIntl();
  return (
    <div className="bg-token-input-background/75 border-token-input-border h-token-button-composer backdrop-blur-sm no-drag flex items-center gap-2 rounded-lg border px-2.5 py-0 text-base leading-[18px] shadow-sm">
      <SearchIcon className="icon-sm text-token-text-secondary" />
      <label className="sr-only" htmlFor="skills-search">
        <FormattedMessage
          id="skills.page.search.label"
          defaultMessage="Search skills"
          description="Label for the skills page search input"
        />
      </label>
      <input
        id="skills-search"
        className="text-token-input-foreground placeholder:text-token-input-placeholder-foreground w-full bg-transparent text-base leading-[18px] outline-none"
        type="text"
        value={searchQuery}
        onChange={(event): void => {
          onSearchQueryChange(event.target.value);
        }}
        placeholder={intl.formatMessage({
          id: "skills.page.search",
          defaultMessage: "Search skills",
          description: "Placeholder for the skills page search input",
        })}
      />
    </div>
  );
}

function SkillsGrid({
  isLoading,
  uniqueSkillCount,
  filteredSkills,
  getScopeBadgeLabel,
  roots,
  onSkillsUpdated,
}: {
  isLoading: boolean;
  uniqueSkillCount: number;
  filteredSkills: Array<{
    skill: AppServer.v2.SkillMetadata;
    scopes: Set<AppServer.v2.SkillScope>;
  }>;
  getScopeBadgeLabel: (args: {
    scope: AppServer.v2.SkillScope;
    skillPath: string;
  }) => string;
  roots: Array<string>;
  onSkillsUpdated?: () => void;
}): ReactElement {
  if (isLoading) {
    return (
      <div className="flex min-h-0 flex-1 items-center justify-center">
        <LargeEmptyState
          title={
            <FormattedMessage
              id="skills.page.loading"
              defaultMessage="Loading skills..."
              description="Loading label on the skills page"
            />
          }
        />
      </div>
    );
  }

  if (uniqueSkillCount === 0) {
    return (
      <div className="flex min-h-0 flex-1 items-center justify-center">
        <LargeEmptyState
          title={
            <FormattedMessage
              id="skills.page.empty"
              defaultMessage="No skills found"
              description="Empty state on the skills page"
            />
          }
        />
      </div>
    );
  }

  if (filteredSkills.length === 0) {
    return (
      <div className="flex min-h-0 flex-1 items-center justify-center">
        <LargeEmptyState
          title={
            <FormattedMessage
              id="skills.page.filteredEmpty"
              defaultMessage="No skills match your filters"
              description="Empty state when filters hide all skills"
            />
          }
          description={
            <FormattedMessage
              id="skills.page.filteredEmptyDescription"
              defaultMessage="Try adjusting your search or scope filters"
              description="Description for filtered skills empty state"
            />
          }
        />
      </div>
    );
  }

  return (
    <div className="skills-grid grid gap-4">
      {filteredSkills.map(({ skill }): ReactElement => {
        const scopeBadges =
          skill.scope === "repo"
            ? [
                <RepoScopeBadge
                  key={`${skill.path}-repo`}
                  label={getScopeBadgeLabel({
                    scope: "repo",
                    skillPath: skill.path,
                  })}
                />,
              ]
            : [];
        const repoRoot =
          skill.scope === "repo"
            ? getRepoRootForSkillPath({ skillPath: skill.path, roots })
            : null;
        return (
          <SkillCard
            key={skill.path}
            skill={skill}
            displayName={getSkillDisplayName(skill)}
            scopeBadges={scopeBadges}
            repoRoot={repoRoot}
            onSkillsUpdated={onSkillsUpdated}
          />
        );
      })}
    </div>
  );
}

function RepoScopeBadge({ label }: { label: string }): ReactElement {
  return (
    <Badge className="border-token-border-default text-token-text-secondary flex items-center gap-1 border bg-transparent px-1.5 py-0.5 text-xs font-medium">
      <FolderIcon className="icon-xxs text-token-text-tertiary" />
      <span>{label}</span>
    </Badge>
  );
}

function RecommendedSkillsGrid({
  isLoading,
  errorMessage,
  skills,
  searchQuery,
  canInstall,
  repoRoot,
  onInstall,
  installedSkillIds,
  installingSkillId,
}: {
  isLoading: boolean;
  errorMessage: string | null;
  skills: Array<RecommendedSkillMetadata>;
  searchQuery: string;
  canInstall: boolean;
  repoRoot: string | null;
  onInstall: (
    skill: RecommendedSkillMetadata,
    installRoot: string | null,
  ) => void;
  installedSkillIds: Set<string>;
  installingSkillId: string | null;
}): ReactElement {
  const uninstalledSkills = skills.filter(
    (skill) => !installedSkillIds.has(skill.id),
  );
  const query = searchQuery.trim().toLowerCase();
  const filteredSkills = uninstalledSkills.filter((skill) => {
    if (query.length === 0) {
      return true;
    }
    const haystack = [
      skill.name,
      skill.description,
      skill.shortDescription ?? "",
    ]
      .join(" ")
      .toLowerCase();
    return haystack.includes(query);
  });

  if (isLoading) {
    return (
      <div className="flex min-h-0 flex-1 items-center justify-center">
        <LargeEmptyState
          title={
            <FormattedMessage
              id="skills.page.loading"
              defaultMessage="Loading skills..."
              description="Loading label on the skills page"
            />
          }
        />
      </div>
    );
  }

  if (errorMessage) {
    return (
      <div className="flex min-h-0 flex-1 items-center justify-center">
        <LargeEmptyState
          title={
            <FormattedMessage
              id="skills.recommended.error"
              defaultMessage="Unable to load recommended skills"
              description="Error title when recommended skills fail to load"
            />
          }
          description={errorMessage}
        />
      </div>
    );
  }

  if (uninstalledSkills.length === 0) {
    return (
      <div className="flex min-h-0 flex-1 items-center justify-center">
        <LargeEmptyState
          title={
            <FormattedMessage
              id="skills.page.empty"
              defaultMessage="No skills found"
              description="Empty state on the skills page"
            />
          }
        />
      </div>
    );
  }

  if (filteredSkills.length === 0) {
    return (
      <div className="flex min-h-0 flex-1 items-center justify-center">
        <LargeEmptyState
          title={
            <FormattedMessage
              id="skills.page.filteredEmpty"
              defaultMessage="No skills match your filters"
              description="Empty state when filters hide all skills"
            />
          }
          description={
            <FormattedMessage
              id="skills.page.filteredEmptyDescription"
              defaultMessage="Try adjusting your search or scope filters"
              description="Description for filtered skills empty state"
            />
          }
        />
      </div>
    );
  }

  return (
    <div className="skills-grid grid gap-4">
      {filteredSkills.map((skill) => {
        const isInstalled = installedSkillIds.has(skill.id);
        const isInstalling = installingSkillId === skill.id;
        return (
          <RecommendedSkillCard
            key={skill.id}
            skill={skill}
            canInstall={canInstall}
            isInstalled={isInstalled}
            isInstalling={isInstalling}
            repoRoot={repoRoot}
            onInstall={onInstall}
          />
        );
      })}
    </div>
  );
}

function getSkillIdFromPath(skillPath: string): string | null {
  const normalized = skillPath.replace(/[\\/]+$/, "");
  const segments = normalized.split(/[\\/]/).filter(Boolean);
  if (segments.length === 0) {
    return null;
  }
  const last = segments[segments.length - 1];
  if (last.toLowerCase() === "skill.md" && segments.length > 1) {
    return segments[segments.length - 2];
  }
  if (last.toLowerCase().endsWith(".md")) {
    return last.slice(0, -3);
  }
  return last;
}

function getRepoRootForSkillPath({
  skillPath,
  roots,
}: {
  skillPath: string;
  roots: Array<string>;
}): string | null {
  let bestRoot: string | null = null;
  for (const root of roots) {
    if (!skillPath.startsWith(root)) {
      continue;
    }
    if (!bestRoot || root.length > bestRoot.length) {
      bestRoot = root;
    }
  }
  return bestRoot;
}
